//! # Universal Signal Map — Logic as Topological Fingerprint
//!
//! Rust implementation mirroring `Gnosis.UniversalSignalMap` in Lean.
//! Translates logical instructions and Polyglot IR operations into
//! deterministic topological pathways (Monster Paths).

use serde::{Deserialize, Serialize};

/// Signal Tokens: the primary operators of the Monster Mesh.
#[derive(Serialize, Deserialize, Clone, Copy, Debug, PartialEq, Eq)]
pub enum SignalToken {
    /// Triton-Stretch (Fork @ residue 0)
    T,
    /// Fork @ residue r
    F { r: u8 },
    /// Race @ residue r
    R { r: u8 },
    /// Fold (Lower / Lens-descent)
    L,
    /// Symmetry shift (Triton rotation)
    S,
    /// Wormhole (ER=EPR) with jump-modulus m
    W { m: u32 },
    /// Vent (Exit path / beta-1 reduction)
    V,
    /// Interference (standing-wave contact / fifth lifecycle force)
    I,
}

/// A Monster Path is a sequence of Signal Tokens.
pub type MonsterPath = Vec<SignalToken>;

pub const WANKEL_AEON_CELLS: u32 = 12;
pub const WANKEL_MONSTER_DEADLINE_PULSE_HOPS: usize = WANKEL_AEON_CELLS as usize * 22;
pub const WANKEL_INTERFERENCE_THEOREM_ID: &str =
    "WankelEngineTheorem.wankel_schedules_interference";
pub const WANKEL_RUNTIME_CERTIFICATE_THEOREM_ID: &str =
    "RuntimeCertificate.wankel_fifth_force_mechanism_has_runtime_certificate";
pub const WANKEL_FAST_PATH_EQUIVALENCE_THEOREM_ID: &str =
    "RuntimeCertificate.wankel_fast_path_preserves_runtime_result_equivalence";
pub const WANKEL_FAST_PATH_COST_DOMINANCE_THEOREM_ID: &str =
    "RuntimeCertificate.wankel_fast_path_cost_dominates_baseline";
pub const WANKEL_AGGREGATE_FAST_PATH_COST_DOMINANCE_THEOREM_ID: &str =
    "RuntimeCertificate.wankel_aggregate_fast_path_cost_dominates_baseline";
pub const WANKEL_ROBUST_FAST_PATH_ESTIMATOR_THEOREM_ID: &str =
    "RuntimeCertificate.wankel_robust_fast_path_estimator_dominates_baseline";
pub const WANKEL_SIGNAL_THEOREM_IDS: [&str; 6] = [
    WANKEL_INTERFERENCE_THEOREM_ID,
    WANKEL_RUNTIME_CERTIFICATE_THEOREM_ID,
    WANKEL_FAST_PATH_EQUIVALENCE_THEOREM_ID,
    WANKEL_FAST_PATH_COST_DOMINANCE_THEOREM_ID,
    WANKEL_AGGREGATE_FAST_PATH_COST_DOMINANCE_THEOREM_ID,
    WANKEL_ROBUST_FAST_PATH_ESTIMATOR_THEOREM_ID,
];

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct WankelRuntimeSignalCertificate {
    pub aeon_cells: u32,
    pub theorem_id: &'static str,
}

impl WankelRuntimeSignalCertificate {
    pub fn certified(&self) -> bool {
        self.aeon_cells == WANKEL_AEON_CELLS
            && self.theorem_id == WANKEL_RUNTIME_CERTIFICATE_THEOREM_ID
    }

    pub fn theorem_ids(&self) -> [&'static str; 6] {
        WANKEL_SIGNAL_THEOREM_IDS
    }
}

pub fn certify_wankel_runtime_signal(aeon_cells: u32) -> Option<WankelRuntimeSignalCertificate> {
    if aeon_cells == WANKEL_AEON_CELLS {
        Some(exact_wankel_runtime_signal_certificate())
    } else {
        None
    }
}

pub fn exact_wankel_runtime_signal_certificate() -> WankelRuntimeSignalCertificate {
    WankelRuntimeSignalCertificate {
        aeon_cells: WANKEL_AEON_CELLS,
        theorem_id: WANKEL_RUNTIME_CERTIFICATE_THEOREM_ID,
    }
}

pub fn five_force_lifecycle_path() -> MonsterPath {
    vec![
        SignalToken::T,
        SignalToken::R { r: 0 },
        SignalToken::L,
        SignalToken::V,
        SignalToken::I,
    ]
}

/// Complexity is measured by the number of rotations (tokens) in the path.
pub fn path_complexity(p: &[SignalToken]) -> usize {
    p.len()
}

/// Polyglot IR Instruction set.
/// Mirrors `PolyglotOp` in Lean.
#[derive(Serialize, Deserialize, Clone, Copy, Debug, PartialEq, Eq)]
pub enum PolyglotOp {
    ConcurrentSpawn,
    SyncJoin,
    Branch,
    Loop,
    Statement,
    Return,
    TryEntry,
    CatchHandler,
    ResourceAcquire,
    ResourceRelease,
    LockAcquire,
    LockRelease,
}

/// Maps Polyglot IR operations to their deterministic Monster Paths.
pub fn map_polyglot(op: PolyglotOp) -> MonsterPath {
    match op {
        PolyglotOp::ConcurrentSpawn => vec![SignalToken::T],
        PolyglotOp::SyncJoin => vec![SignalToken::L],
        PolyglotOp::Branch => vec![SignalToken::R { r: 0 }],
        PolyglotOp::Loop => vec![SignalToken::S, SignalToken::T],
        PolyglotOp::Statement => vec![SignalToken::S],
        PolyglotOp::Return => vec![SignalToken::V],
        PolyglotOp::TryEntry => vec![SignalToken::T, SignalToken::S],
        PolyglotOp::CatchHandler => vec![SignalToken::L, SignalToken::S],
        PolyglotOp::ResourceAcquire => vec![SignalToken::W { m: 1 }],
        PolyglotOp::ResourceRelease => vec![SignalToken::W { m: 2 }],
        PolyglotOp::LockAcquire => vec![SignalToken::R { r: 1 }],
        PolyglotOp::LockRelease => vec![SignalToken::F { r: 0 }],
    }
}

/// Maps core instruction names to their deterministic Monster Paths.
/// These are the "Universally Necessary Pathways".
pub fn map_instruction(op: &str) -> MonsterPath {
    match op.to_uppercase().as_str() {
        "AND" => vec![SignalToken::F { r: 0 }, SignalToken::S, SignalToken::L],
        "OR" => vec![SignalToken::F { r: 1 }, SignalToken::S, SignalToken::L],
        "XOR" => vec![SignalToken::F { r: 2 }, SignalToken::S, SignalToken::L],
        "SHL" => vec![SignalToken::T, SignalToken::T],
        "SHR" => vec![SignalToken::L, SignalToken::L],
        "INV" => vec![SignalToken::S, SignalToken::S],
        "JMP" => vec![SignalToken::W { m: 10 }],
        _ => vec![],
    }
}

/// The "Colors" of Resonance.
#[derive(Serialize, Deserialize, Clone, Copy, Debug, PartialEq, Eq)]
pub enum ResonanceColor {
    White,
    Pink,
    Brown,
}

pub fn resonance_alpha(c: ResonanceColor) -> u32 {
    match c {
        ResonanceColor::White => 0,
        ResonanceColor::Pink => 1,
        ResonanceColor::Brown => 2,
    }
}

/// Each resonance color maps to a specific manifold saturation level.
pub fn manifold_saturation(c: ResonanceColor) -> f64 {
    10.0 * 3.0f64.powi(resonance_alpha(c) as i32)
}

/// The dynamic runtime generates unique branches based on variable data.
pub fn dynamic_branch(context: u32) -> MonsterPath {
    vec![
        SignalToken::F {
            r: (context % 3) as u8,
        },
        SignalToken::S,
    ]
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn wankel_runtime_signal_certificate_is_fail_closed() {
        let certificate = exact_wankel_runtime_signal_certificate();

        assert!(certificate.certified());
        assert_eq!(certificate.aeon_cells, WANKEL_AEON_CELLS);
        assert_eq!(certificate.theorem_ids(), WANKEL_SIGNAL_THEOREM_IDS);
        assert_eq!(
            certify_wankel_runtime_signal(WANKEL_AEON_CELLS),
            Some(certificate)
        );
        assert_eq!(certify_wankel_runtime_signal(WANKEL_AEON_CELLS + 1), None);
    }

    #[test]
    fn five_force_lifecycle_path_ends_in_interference() {
        assert_eq!(
            five_force_lifecycle_path(),
            vec![
                SignalToken::T,
                SignalToken::R { r: 0 },
                SignalToken::L,
                SignalToken::V,
                SignalToken::I,
            ]
        );
    }
}
